   140→  if (fetchPromise) return fetchPromise;
   141→  fetchPromise = fetch("https://ipapi.co/json/", { signal: AbortSignal.timeout(3000) })
   142→    .then(r => r.json())
   143→    .then(d => {
   144→      cachedCountryCode = d.country_code || "";
   145→      return cachedCountryCode as string;
   146→    })
   147→    .catch(() => { cachedCountryCode = ""; return ""; });
   148→  return fetchPromise;
   149→}
   150→
   151→export async function getCountryCode(): Promise<string> {
   152→  const byTz = detectCountryByTimezone();
   153→  if (byTz) return byTz;
   154→  return fetchCountryCode();
   155→}
   156→
   157→export function useCurrency(forceSAR = false): CurrencyInfo {
   158→  const [countryCode, setCountryCode] = useState<string>(() => {
   159→    if (forceSAR) return "SA";
   160→    return detectCountryByTimezone();
   161→  });
   162→
   163→  useEffect(() => {
   164→    if (forceSAR) return;
   165→    if (countryCode) return;
   166→    fetchCountryCode().then(code => {
   167→      if (code) setCountryCode(code);
   168→    });
   169→  }, [forceSAR]);
   170→
   171→  if (forceSAR) {
   172→    return buildCurrencyInfo("SA", FALLBACK);
   173→  }
   174→
   175→  const def = CURRENCY_MAP[countryCode] || FALLBACK;
   176→  return buildCurrencyInfo(countryCode || "SA", def);
   177→}
   178→
   179→export function useSARCurrency(): CurrencyInfo {
   180→  return buildCurrencyInfo("SA", FALLBACK);
   181→}
   182→
   183→export function getCurrencyForCountry(countryCode: string): CurrencyDef {
   184→  return CURRENCY_MAP[countryCode] || FALLBACK;
   185→}
