    42→    if (line.startsWith("- ") || line.startsWith("• ")) {
    43→      return <li key={i} className="text-xs text-black/75 dark:text-white/75 mr-3 list-disc leading-relaxed">{line.slice(2)}</li>;
    44→    }
    45→    if (line.trim() === "") return <div key={i} className="h-1.5" />;
    46→    const parts = line.split(/\*\*(.*?)\*\*/g);
    47→    if (parts.length > 1) return (
    48→      <p key={i} className="text-xs text-black/75 dark:text-white/75 leading-relaxed">
    49→        {parts.map((part, j) => j % 2 === 1 ? <strong key={j} className="font-bold text-black dark:text-white">{part}</strong> : part)}
    50→      </p>
    51→    );
    52→    return <p key={i} className="text-xs text-black/75 dark:text-white/75 leading-relaxed">{line}</p>;
